import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:wishperlog/features/ai/data/gemini_note_classifier.dart';
import 'package:wishperlog/features/ai/data/groq_note_classifier.dart';
import 'package:wishperlog/shared/models/enums.dart';

/// Routes classification requests through the active provider with automatic
/// fallback: Gemini → Groq → local (no enrichment).
class AiClassifierRouter {
  static const _prefsKey = 'ai_provider';

  final GeminiNoteClassifier _gemini;
  final GroqNoteClassifier _groq;
  AiProvider _activeProvider = AiProvider.auto;

  AiClassifierRouter()
      : _gemini = GeminiNoteClassifier(),
        _groq = GroqNoteClassifier();

  AiProvider get activeProvider => _activeProvider;

  bool get geminiConfigured => _gemini.isConfigured;
  bool get groqConfigured => _groq.isConfigured;

  /// Load preference from SharedPreferences
  Future<void> hydrate() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final stored = prefs.getString(_prefsKey);
      _activeProvider = AiProvider.values.firstWhere(
        (p) => p.name == stored,
        orElse: () => AiProvider.auto,
      );
    } catch (e) {
      debugPrint('[AiClassifierRouter] hydrate error: $e');
    }
  }

  /// Persist chosen provider
  Future<void> setProvider(AiProvider provider) async {
    _activeProvider = provider;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString(_prefsKey, provider.name);
    } catch (e) {
      debugPrint('[AiClassifierRouter] setProvider error: $e');
    }
  }

  /// Classify a note using the configured provider chain.
  Future<GeminiClassificationResult> classify(String rawTranscript) async {
    switch (_activeProvider) {
      case AiProvider.groq:
        return await _tryGroq(rawTranscript) ?? _localFallback(rawTranscript);
      case AiProvider.gemini:
        return await _gemini.classify(rawTranscript);
      case AiProvider.huggingface:
      case AiProvider.auto:
        // Try Gemini first, then Groq, then local
        try {
          return await _gemini.classify(rawTranscript);
        } catch (e) {
          debugPrint('[AiClassifierRouter] Gemini failed, trying Groq: $e');
          return await _tryGroq(rawTranscript) ?? _localFallback(rawTranscript);
        }
    }
  }

  Future<GeminiClassificationResult?> _tryGroq(String rawTranscript) async {
    if (!_groq.isConfigured) return null;
    try {
      return await _groq.classify(rawTranscript);
    } catch (e) {
      debugPrint('[AiClassifierRouter] Groq failed: $e');
      return null;
    }
  }

  GeminiClassificationResult _localFallback(String raw) {
    final cleaned = raw.trim();
    final oneLine = cleaned.replaceAll('\n', ' ');
    return GeminiClassificationResult(
      title: oneLine.length <= 60 ? oneLine : '${oneLine.substring(0, 60)}...',
      category: NoteCategory.general,
      priority: NotePriority.medium,
      extractedDate: null,
      cleanBody: cleaned,
      model: 'local-fallback',
      wasFallback: true,
    );
  }
}

import 'dart:async';

import 'package:flutter/foundation.dart';
import 'package:cloud_firestore/cloud_firestore.dart';
import 'package:firebase_auth/firebase_auth.dart';
import 'package:wishperlog/core/di/injection_container.dart';
import 'package:wishperlog/core/storage/isar_note_store.dart';
import 'package:wishperlog/features/sync/data/external_sync_service.dart';
import 'package:wishperlog/shared/events/note_event_bus.dart';
import 'package:wishperlog/shared/models/enums.dart';
import 'package:wishperlog/shared/models/note.dart';
import 'package:wishperlog/features/ai/data/ai_classifier_router.dart';

class AiProcessingService {
  AiProcessingService({
    AiClassifierRouter? router,
    FirebaseAuth? auth,
    FirebaseFirestore? firestore,
    IsarNoteStore? isarNoteStore,
    ExternalSyncService? externalSync,
    NoteEventBus? noteEventBus,
  }) : _router = router ?? sl<AiClassifierRouter>(),
       _auth = auth ?? FirebaseAuth.instance,
       _firestore = firestore ?? FirebaseFirestore.instance,
       _isarNoteStore = isarNoteStore ?? IsarNoteStore.instance,
       _externalSync = externalSync ?? sl<ExternalSyncService>(),
       _noteEventBus = noteEventBus ?? NoteEventBus.instance;

  final AiClassifierRouter _router;
  final FirebaseAuth _auth;
  final FirebaseFirestore _firestore;
  final IsarNoteStore _isarNoteStore;
  final ExternalSyncService _externalSync;
  final NoteEventBus _noteEventBus;

  StreamSubscription<String>? _noteSavedSubscription;
  final Set<String> _inFlightNoteIds = <String>{};
  bool _sweepRunning = false;

  void start() {
    unawaited(_sweepPendingOnce());
    _noteSavedSubscription ??= _noteEventBus.onNoteSaved.listen((noteId) {
      unawaited(processNoteById(noteId));
    });
  }

  Future<void> flushPendingQueue() async {
    await _sweepPendingOnce();
  }

  void dispose() {
    _noteSavedSubscription?.cancel();
    _noteSavedSubscription = null;
  }

  Future<void> _sweepPendingOnce() async {
    if (_sweepRunning) {
      return;
    }
    _sweepRunning = true;

    try {
      final pending = await _isarNoteStore.getPendingAiNotes();

      for (final note in pending) {
        await processNoteById(note.noteId);
      }
    } catch (_) {
      // Avoid crashing the UI if SQLite is temporarily unavailable during startup.
    } finally {
      _sweepRunning = false;
    }
  }

  Future<void> processNoteById(String noteId) async {
    final trimmedId = noteId.trim();
    if (trimmedId.isEmpty || _inFlightNoteIds.contains(trimmedId)) {
      return;
    }

    _inFlightNoteIds.add(trimmedId);
    try {
      final note = await _isarNoteStore.getByNoteId(trimmedId);
      if (note == null || note.status != NoteStatus.pendingAi) {
        return;
      }

      final result = await _router.classify(note.rawTranscript);
      final now = DateTime.now();

      final activeNote = note.copyWith(
        title: result.title,
        category: result.category,
        priority: result.priority,
        extractedDate: result.extractedDate,
        clearExtractedDate: result.extractedDate == null,
        cleanBody: result.cleanBody,
        aiModel: result.model,
        status: NoteStatus.active,
        updatedAt: now,
        syncedAt: now,
      );

      final externalResult = await _externalSync.syncExternalForNote(
        activeNote,
      );
      final externallySyncedNote = externalResult.note;

      await _isarNoteStore.put(externallySyncedNote);

      await _syncToFirestore(externallySyncedNote);
    } catch (e, st) {
      // Log the exact error to diagnose AI failures.
      debugPrint('[AiProcessingService] Error processing $trimmedId: $e');
      debugPrintStack(stackTrace: st);
      // Keep note as pendingAi and let future events/sweeps retry.
    } finally {
      _inFlightNoteIds.remove(trimmedId);
    }
  }

  Future<bool> _syncToFirestore(Note note) async {
    var user = _auth.currentUser;
    // Wait for auth to hydrate in isolated contexts
    if (user == null) {
      try {
        user = await _auth
            .authStateChanges()
            .firstWhere((u) => u != null, orElse: () => null as User?)
            .timeout(const Duration(seconds: 2));
      } catch (_) {}
    }

    final uid = user?.uid ?? note.uid;
    if (uid.isEmpty || uid == 'local_anonymous') {
      debugPrint(
        '[AiProcessingService] Firebase sync skipped: user not authenticated ($uid)',
      );
      return false; // Return false so it is retried later!
    }

    try {
      await _firestore
          .collection('users')
          .doc(uid)
          .collection('notes')
          .doc(note.noteId)
          .set(note.toFirestoreJson(), SetOptions(merge: true));
      return true;
    } catch (e) {
      debugPrint('[AiProcessingService] Firestore sync error: $e');
      return false;
    }
  }
}

import 'dart:convert';

import 'package:google_generative_ai/google_generative_ai.dart';
import 'package:wishperlog/core/config/app_env.dart';
import 'package:wishperlog/shared/models/enums.dart';
import 'package:wishperlog/shared/models/note_helpers.dart';

class GeminiClassificationResult {
  GeminiClassificationResult({
    required this.title,
    required this.category,
    required this.priority,
    required this.extractedDate,
    required this.cleanBody,
    required this.model,
    required this.wasFallback,
  });

  final String title;
  final NoteCategory category;
  final NotePriority priority;
  final DateTime? extractedDate;
  final String cleanBody;
  final String model;
  final bool wasFallback;
}

class GeminiNoteClassifier {
  GeminiNoteClassifier({
    String? apiKey,
    GenerativeModel? model,
  })  : _apiKey = apiKey ?? AppEnv.geminiApiKey,
        _providedModel = model;

  static const String systemPrompt =
      'You are a smart personal note editor and classifier. Return JSON strictly containing title, category, priority, clean_body, extracted_date. '
      'Your objectives: 1. Categorize exactly into (Tasks, Reminders, Ideas, Follow-up, Journal, or General). '
      '2. Fix grammar, spelling, semantics and beautify the text as "clean_body" while keeping the original meaning. '
      '3. Set "priority" to high, medium, or low. '
      '4. Provide a descriptive "title". '
      '5. Set "extracted_date" to ISO8601 if a date is mentioned, else null. '
      'Output ONLY raw and valid JSON object payload without backticks or markdown fences!';

  final String _apiKey;
  final GenerativeModel? _providedModel;

  bool get isConfigured => _providedModel != null || _apiKey.isNotEmpty;

  Future<GeminiClassificationResult> classify(String rawTranscript) async {
    final text = rawTranscript.trim();
    if (text.isEmpty) {
      return _fallback(rawTranscript, model: 'none');
    }

    if (!isConfigured) {
      return _fallback(rawTranscript, model: 'offline-fallback');
    }

    final model = _providedModel ??
        GenerativeModel(model: 'gemini-2.5-flash-lite', apiKey: _apiKey);

    const maxAttempts = 3;
    for (var attempt = 0; attempt < maxAttempts; attempt++) {
      try {
        final response = await model.generateContent([
          Content.text(systemPrompt),
          Content.text('Raw input: $text'),
        ]);

        final payload = response.text?.trim();
        if (payload == null || payload.isEmpty) {
          return _fallback(rawTranscript, model: 'gemini-2.5-flash-lite');
        }

        return _parseOrFallback(
          rawTranscript: rawTranscript,
          payload: payload,
          model: 'gemini-2.5-flash-lite',
        );
      } catch (e) {
        final errorStr = e.toString();
        final isRateLimit = errorStr.contains('429') ||
            errorStr.contains('quota') ||
            errorStr.contains('rate limit') ||
            errorStr.contains('RESOURCE_EXHAUSTED');

        if (!isRateLimit || attempt >= maxAttempts - 1) {
          // Not a rate limit error or exhausted retries → graceful fallback
          return _fallback(rawTranscript, model: 'gemini-2.5-flash-lite');
        }

        // Try to parse "retry in Xs" from the error message
        Duration backoff = Duration(seconds: 2 * (attempt + 1));
        final retryMatch = RegExp(r'retry in (\d+(?:\.\d+)?)s').firstMatch(errorStr);
        if (retryMatch != null) {
          final seconds = double.tryParse(retryMatch.group(1) ?? '') ?? 0;
          backoff = Duration(milliseconds: (seconds * 1000).ceil() + 500);
        }

        await Future<void>.delayed(backoff);
      }
    }

    return _fallback(rawTranscript, model: 'gemini-2.5-flash-lite');
  }

  GeminiClassificationResult _parseOrFallback({
    required String rawTranscript,
    required String payload,
    required String model,
  }) {
    try {
      final jsonBody = _extractJson(payload);
      final decoded = jsonDecode(jsonBody);
      if (decoded is! Map<String, dynamic>) {
        return _fallback(rawTranscript, model: model);
      }

      final title = (decoded['title'] as String?)?.trim();
      final cleanBody = (decoded['clean_body'] as String?)?.trim();

      return GeminiClassificationResult(
        title: (title == null || title.isEmpty)
            ? _fallbackTitle(rawTranscript)
            : title,
        category: parseCategory(
          (decoded['category'] as String?) ?? NoteCategory.general.name,
        ),
        priority: parsePriority(
          (decoded['priority'] as String?) ?? NotePriority.medium.name,
        ),
        extractedDate: _parseDate(decoded['extracted_date']),
        cleanBody: (cleanBody == null || cleanBody.isEmpty)
            ? rawTranscript.trim()
            : cleanBody,
        model: model,
        wasFallback: false,
      );
    } catch (_) {
      return _fallback(rawTranscript, model: model);
    }
  }

  String _extractJson(String payload) {
    final noFence = payload
        .replaceAll('```json', '')
        .replaceAll('```', '')
        .trim();

    final start = noFence.indexOf('{');
    final end = noFence.lastIndexOf('}');
    if (start >= 0 && end >= start) {
      return noFence.substring(start, end + 1);
    }
    return noFence;
  }

  DateTime? _parseDate(dynamic value) {
    if (value == null) {
      return null;
    }
    final raw = value.toString().trim();
    if (raw.isEmpty || raw.toLowerCase() == 'null') {
      return null;
    }
    return DateTime.tryParse(raw)?.toLocal();
  }

  GeminiClassificationResult _fallback(String rawTranscript, {required String model}) {
    final cleaned = rawTranscript.trim();
    return GeminiClassificationResult(
      title: _fallbackTitle(rawTranscript),
      category: NoteCategory.general,
      priority: NotePriority.medium,
      extractedDate: null,
      cleanBody: cleaned.isEmpty ? rawTranscript : cleaned,
      model: model,
      wasFallback: true,
    );
  }

  String _fallbackTitle(String text) {
    final oneLine = text.replaceAll('\n', ' ').trim();
    if (oneLine.isEmpty) {
      return 'Quick note';
    }
    if (oneLine.length <= 60) {
      return oneLine;
    }
    return '${oneLine.substring(0, 60).trimRight()}...';
  }
}

import 'dart:convert';

import 'package:flutter/foundation.dart';
import 'package:http/http.dart' as http;
import 'package:wishperlog/core/config/app_env.dart';
import 'package:wishperlog/features/ai/data/gemini_note_classifier.dart';
import 'package:wishperlog/shared/models/enums.dart';
import 'package:wishperlog/shared/models/note_helpers.dart';

/// Calls Groq Chat API (OpenAI-compatible) to classify notes.
/// Uses llama-3.3-70b-versatile by default.
class GroqNoteClassifier {
  static const _baseUrl = 'https://api.groq.com/openai/v1/chat/completions';
  static const _model = 'llama-3.3-70b-versatile';

  final String _apiKey;

  GroqNoteClassifier({String? apiKey}) : _apiKey = apiKey ?? AppEnv.groqApiKey;

  bool get isConfigured => _apiKey.isNotEmpty;

  Future<GeminiClassificationResult?> classify(String rawTranscript) async {
    if (!isConfigured || rawTranscript.trim().isEmpty) return null;

    try {
      final response = await http.post(
        Uri.parse(_baseUrl),
        headers: {
          'Authorization': 'Bearer $_apiKey',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({
          'model': _model,
          'messages': [
            {'role': 'system', 'content': GeminiNoteClassifier.systemPrompt},
            {'role': 'user', 'content': 'Raw input: ${rawTranscript.trim()}'},
          ],
          'temperature': 0.3,
          'max_tokens': 512,
        }),
      ).timeout(const Duration(seconds: 15));

      if (response.statusCode != 200) {
        debugPrint('[GroqClassifier] API error ${response.statusCode}: ${response.body}');
        return null;
      }

      final body = jsonDecode(response.body) as Map<String, dynamic>;
      final content = (body['choices'] as List?)?.first?['message']?['content'] as String?;
      if (content == null || content.isEmpty) return null;

      return _parse(rawTranscript, content.trim());
    } catch (e) {
      debugPrint('[GroqClassifier] classify error: $e');
      return null;
    }
  }

  GeminiClassificationResult? _parse(String raw, String payload) {
    try {
      final noFence = payload
          .replaceAll('```json', '')
          .replaceAll('```', '')
          .trim();
      final start = noFence.indexOf('{');
      final end = noFence.lastIndexOf('}');
      if (start < 0 || end < start) return null;

      final decoded = jsonDecode(noFence.substring(start, end + 1)) as Map<String, dynamic>;
      final title = (decoded['title'] as String?)?.trim();
      final cleanBody = (decoded['clean_body'] as String?)?.trim();
      return GeminiClassificationResult(
        title: (title == null || title.isEmpty) ? _fallbackTitle(raw) : title,
        category: parseCategory((decoded['category'] as String?) ?? NoteCategory.general.name),
        priority: parsePriority((decoded['priority'] as String?) ?? NotePriority.medium.name),
        extractedDate: _parseDate(decoded['extracted_date']),
        cleanBody: (cleanBody == null || cleanBody.isEmpty) ? raw.trim() : cleanBody,
        model: 'groq/$_model',
        wasFallback: false,
      );
    } catch (_) {
      return null;
    }
  }

  DateTime? _parseDate(dynamic value) {
    if (value == null) return null;
    final raw = value.toString().trim();
    if (raw.isEmpty || raw.toLowerCase() == 'null') return null;
    return DateTime.tryParse(raw)?.toLocal();
  }

  String _fallbackTitle(String text) {
    final oneLine = text.replaceAll('\n', ' ').trim();
    if (oneLine.length <= 60) return oneLine;
    return '${oneLine.substring(0, 60).trimRight()}...';
  }
}

