      child: TweenAnimationBuilder<int>(
        tween: IntTween(begin: 0, end: count),
        duration: AppDurations.countRoll,
        builder: (context, value, _) {
          return Text(
            '$value',
            style: TextStyle(
              color: context.textPri,
              fontWeight: FontWeight.w800,
              fontSize: 12,
            ),
          );
        },
      ),
    );
  }
