class SyncRunResult {
  SyncRunResult({required this.processed, required this.updated});

  final int processed;
  final int updated;
}

class ExternalSyncService {
  ExternalSyncService({
    FirebaseAuth? auth,
    FirebaseFirestore? firestore,
    IsarNoteStore? isarNoteStore,
    GoogleSignIn? googleSignIn,
  }) : _auth = auth ?? FirebaseAuth.instance,
       _firestore = firestore ?? FirebaseFirestore.instance,
       _isarNoteStore = isarNoteStore ?? IsarNoteStore.instance,
       _googleSignIn =
           googleSignIn ??
           GoogleSignIn(
             scopes: [
               gcal.CalendarApi.calendarScope,
               gtasks.TasksApi.tasksScope,
               'email',
             ],
           );

  final FirebaseAuth _auth;
  final FirebaseFirestore _firestore;
  final IsarNoteStore _isarNoteStore;
  final GoogleSignIn _googleSignIn;

  Future<bool> ensureGoogleConnected() async {
    try {
      final account = await _googleSignIn.signInSilently();
      return account != null;
    } catch (_) {
      return false;
    }
  }

  Future<bool> reconnectGoogle() async {
    try {
      final account = await _googleSignIn.signIn();
      return account != null;
    } catch (_) {
      return false;
    }
  }

  Future<SyncRunResult> syncNow() async {
    final active = await _isarNoteStore.getAllActive();

    var updated = 0;
    for (final note in active) {
      final result = await syncExternalForNote(note);
      if (result.noteChanged) {
        await _isarNoteStore.put(result.note);
        await _syncNoteToFirestore(result.note);
        updated += 1;
      }
    }

    return SyncRunResult(processed: active.length, updated: updated);
  }

  Future<int> syncGoogleTaskCompletions() async {
    final account = await _googleSignIn.signInSilently();
    if (account == null) {
      return 0;
    }

    final headers = await account.authHeaders;
    final client = HeaderClient(headers);

    try {
      final tasksApi = gtasks.TasksApi(client);
      final remoteTasks = await tasksApi.tasks.list(
        '@default',
        showCompleted: true,
        showHidden: true,
        maxResults: 200,
      );

      final completedIds = (remoteTasks.items ?? const <gtasks.Task>[])
          .where((task) => task.id != null && task.status == 'completed')
          .map((task) => task.id!)
          .toSet();

      if (completedIds.isEmpty) {
        return 0;
      }

      final linkedTaskNotes = (await _isarNoteStore.getAllActive())
          .where((note) => note.gtaskId != null)
          .toList();

      var archivedCount = 0;
      for (final note in linkedTaskNotes) {
        final taskId = note.gtaskId;
        if (taskId == null || !completedIds.contains(taskId)) {
          continue;
        }

        final archived = note.copyWith(
          status: NoteStatus.archived,
          updatedAt: DateTime.now(),
          syncedAt: DateTime.now(),
        );

        await _isarNoteStore.put(archived);
        await _syncNoteToFirestore(archived);
        archivedCount += 1;
      }

      return archivedCount;
    } catch (_) {
      return 0;
    } finally {
      client.close();
    }
  }

  Future<SyncNoteResult> syncExternalForNote(Note note) async {
    if (note.status != NoteStatus.active) {
      return SyncNoteResult(note: note, noteChanged: false);
    }

    final account = await _googleSignIn.signInSilently();
    if (account == null) {
      return SyncNoteResult(note: note, noteChanged: false);
    }

    final headers = await account.authHeaders;
    final client = HeaderClient(headers);

    try {
      var updated = note;
      var changed = false;

      if (note.category == NoteCategory.reminders &&
          note.extractedDate != null &&
          note.gcalEventId == null) {
        final calendar = gcal.CalendarApi(client);
        final createdEventId = await _createCalendarReminderIfMissing(
          api: calendar,
          note: updated,
        );
        if (createdEventId != null) {
          updated = updated.copyWith(
            gcalEventId: createdEventId,
            updatedAt: DateTime.now(),
          );
          changed = true;
        }
      }

      if (updated.category == NoteCategory.tasks && updated.gtaskId == null) {
        final tasks = gtasks.TasksApi(client);
        final createdTaskId = await _createGoogleTask(tasks, updated);
        if (createdTaskId != null) {
          updated = updated.copyWith(
            gtaskId: createdTaskId,
            updatedAt: DateTime.now(),
          );
          changed = true;
        }
      }

      if (changed) {
        updated = updated.copyWith(syncedAt: DateTime.now());
      }

      return SyncNoteResult(note: updated, noteChanged: changed);
    } catch (_) {
      return SyncNoteResult(note: note, noteChanged: false);
    } finally {
      client.close();
    }
  }

  Future<String?> _createCalendarReminderIfMissing({
    required gcal.CalendarApi api,
    required Note note,
  }) async {
    final target = note.extractedDate!;
    final start = target.subtract(const Duration(days: 2)).toUtc();
    final end = target.add(const Duration(days: 2)).toUtc();

    final events = await api.events.list(
      'primary',
      timeMin: start,
      timeMax: end,
      singleEvents: true,
      maxResults: 50,
    );

    final title = note.title.trim();
    final existingTitles =
        events.items
            ?.map((e) => (e.summary ?? '').trim())
            .where((s) => s.isNotEmpty)
            .toList() ??
        const <String>[];

    final hasDuplicate = _hasFuzzyDuplicate(title, existingTitles);
    if (hasDuplicate) {
      return null;
    }

    final event = gcal.Event(
      summary: title,
      description: note.cleanBody,
      start: gcal.EventDateTime(dateTime: target.toUtc()),
      end: gcal.EventDateTime(
        dateTime: target.toUtc().add(const Duration(minutes: 30)),
      ),
    );

    final created = await api.events.insert(event, 'primary');
    return created.id;
  }

  bool _hasFuzzyDuplicate(String title, List<String> existingTitles) {
    if (title.isEmpty || existingTitles.isEmpty) {
      return false;
    }

    final fuzzy = Fuzzy<String>(
      existingTitles,
      options: FuzzyOptions<String>(threshold: 0.15, shouldNormalize: true),
    );

    final result = fuzzy.search(title, 1);
    if (result.isEmpty) {
      return false;
    }

    // threshold 0.15 ~= 85% similarity requirement.
    return result.first.score <= 0.15;
  }

  Future<String?> _createGoogleTask(gtasks.TasksApi api, Note note) async {
    final task = gtasks.Task(
      title: note.title,
      notes: note.cleanBody,
      due: note.extractedDate?.toUtc().toIso8601String(),
    );
    final created = await api.tasks.insert(task, '@default');
    return created.id;
  }

  Future<void> _syncNoteToFirestore(Note note) async {
    var user = _auth.currentUser;
    if (user == null) {
      try {
        user = await _auth.authStateChanges().first;
      } catch (_) {}
    }

    final uid = user?.uid ?? note.uid;
    if (uid.isEmpty || uid == 'local_anonymous') {
      return;
    }

    await _firestore
        .collection('users')
        .doc(uid)
        .collection('notes')
        .doc(note.noteId)
        .set(note.toFirestoreJson(), SetOptions(merge: true));
  }
}

class SyncNoteResult {
  SyncNoteResult({required this.note, required this.noteChanged});

  final Note note;
  final bool noteChanged;
}

import 'dart:async';

import 'package:firebase_core/firebase_core.dart';
import 'package:firebase_messaging/firebase_messaging.dart';
import 'package:flutter/foundation.dart';
import 'package:wishperlog/features/auth/data/repositories/user_repository.dart';
import 'package:wishperlog/features/sync/data/firestore_note_sync_service.dart';
import 'package:wishperlog/firebase_options.dart';

bool _fcmBackgroundHandlerRegistered = false;

void ensureFcmBackgroundHandlerRegistered() {
  if (_fcmBackgroundHandlerRegistered) {
    return;
  }
  FirebaseMessaging.onBackgroundMessage(firebaseMessagingBackgroundHandler);
  _fcmBackgroundHandlerRegistered = true;
}

class FcmSyncService {
  FcmSyncService({
    FirebaseMessaging? messaging,
    UserRepository? users,
    FirestoreNoteSyncService? noteSync,
  }) : _messaging = messaging ?? FirebaseMessaging.instance,
       _users = users ?? UserRepository(),
       _noteSync = noteSync ?? FirestoreNoteSyncService();

  final FirebaseMessaging _messaging;
  final UserRepository _users;
  final FirestoreNoteSyncService _noteSync;

  bool _initialized = false;
  StreamSubscription<String>? _tokenRefreshSub;
  StreamSubscription<RemoteMessage>? _messageSub;
  StreamSubscription<RemoteMessage>? _messageOpenedSub;

  Future<void> initialize() async {
    ensureFcmBackgroundHandlerRegistered();

    if (_initialized) {
      return;
    }
    _initialized = true;

    try {
      debugPrint('[FcmSyncService] Getting FCM token...');
      final token = await _messaging.getToken().timeout(
        const Duration(seconds: 5),
        onTimeout: () {
          debugPrint('[FcmSyncService] Token retrieval timed out');
          return null;
        },
      );
      if (token != null && token.isNotEmpty) {
        debugPrint('[FcmSyncService] Got token, updating user...');
        await _users.updateFcmToken(token).timeout(
          const Duration(seconds: 5),
          onTimeout: () {
            debugPrint('[FcmSyncService] Token update timed out');
            return;
          },
        );
      }
    } catch (e) {
      debugPrint('[FcmSyncService] Error getting token: $e');
    }

    _tokenRefreshSub ??= _messaging.onTokenRefresh.listen((token) async {
      await _users.updateFcmToken(token);
    });

    _messageSub ??= FirebaseMessaging.onMessage.listen(_handleRemoteMessage);
    _messageOpenedSub ??= FirebaseMessaging.onMessageOpenedApp.listen(
      _handleRemoteMessage,
    );
  }

  Future<NotificationSettings> requestPermission() {
    return _messaging.requestPermission(
      alert: true,
      announcement: false,
      badge: true,
      carPlay: false,
      criticalAlert: false,
      provisional: false,
      sound: true,
    );
  }

  Future<NotificationSettings> getNotificationSettings() {
    return _messaging.getNotificationSettings();
  }

  Future<void> dispose() async {
    await _tokenRefreshSub?.cancel();
    await _messageSub?.cancel();
    await _messageOpenedSub?.cancel();
    _tokenRefreshSub = null;
    _messageSub = null;
    _messageOpenedSub = null;
    _initialized = false;
  }

  Future<void> _handleRemoteMessage(RemoteMessage message) async {
    final type = message.data['type'];
    final noteId = message.data['note_id'];
    final status = message.data['status'];

    if (type == 'note_status_changed' &&
        noteId is String &&
        noteId.trim().isNotEmpty &&
        status is String) {
      await _noteSync.applyStatusFromPush(noteId: noteId, status: status);
      return;
    }

    if (type == 'note_updated' &&
        noteId is String &&
        noteId.trim().isNotEmpty) {
      await _noteSync.syncNoteById(noteId);
    }
  }
}

@pragma('vm:entry-point')
Future<void> firebaseMessagingBackgroundHandler(RemoteMessage message) async {
  try {
    if (Firebase.apps.isEmpty) {
      await Firebase.initializeApp(
        options: DefaultFirebaseOptions.currentPlatform,
      );
    }
    final noteSync = FirestoreNoteSyncService();

    final type = message.data['type'];
    final noteId = message.data['note_id'];
    final status = message.data['status'];

    if (type == 'note_status_changed' &&
        noteId is String &&
        noteId.trim().isNotEmpty &&
        status is String) {
      await noteSync.applyStatusFromPush(noteId: noteId, status: status);
      return;
    }

    if (type == 'note_updated' &&
        noteId is String &&
        noteId.trim().isNotEmpty) {
      await noteSync.syncNoteById(noteId);
    }
  } catch (error) {
    debugPrint('FCM background handler error: $error');
  }
}

import 'dart:async';

import 'package:cloud_firestore/cloud_firestore.dart';
import 'package:firebase_auth/firebase_auth.dart';
import 'package:flutter/foundation.dart';
import 'package:wishperlog/core/storage/isar_note_store.dart';
import 'package:wishperlog/shared/models/note.dart';
import 'package:wishperlog/shared/models/note_helpers.dart';

class FirestoreNoteSyncService {
  FirestoreNoteSyncService({
    FirebaseAuth? auth,
    FirebaseFirestore? firestore,
    IsarNoteStore? isarNoteStore,
  }) : _auth = auth ?? FirebaseAuth.instance,
       _firestore = firestore ?? FirebaseFirestore.instance,
       _isarNoteStore = isarNoteStore ?? IsarNoteStore.instance;

  final FirebaseAuth _auth;
  final FirebaseFirestore _firestore;
  final IsarNoteStore _isarNoteStore;

  bool _started = false;
  bool _isRestarting = false;
  StreamSubscription<User?>? _authSub;
  StreamSubscription<QuerySnapshot<Map<String, dynamic>>>? _noteSub;

  Future<void> start() async {
    if (_started) {
      return;
    }
    _started = true;

    _authSub = _auth.authStateChanges().listen(
      (user) {
        _attachUserListener(user);
      },
      onError: (Object error, StackTrace st) {
        debugPrint('[FirestoreNoteSyncService] Auth stream error: $error');
        debugPrintStack(stackTrace: st);
      },
    );

    await _attachUserListener(_auth.currentUser);
  }

  Future<void> stop() async {
    _started = false;
    await _noteSub?.cancel();
    await _authSub?.cancel();
    _noteSub = null;
    _authSub = null;
  }

  Future<void> _attachUserListener(User? user) async {
    await _noteSub?.cancel();
    _noteSub = null;

    final uid = user?.uid.trim() ?? '';
    if (uid.isEmpty) {
      debugPrint(
        '[FirestoreNoteSyncService] No authenticated user, listener idle',
      );
      return;
    }

    _noteSub = _firestore
        .collection('users')
        .doc(uid)
        .collection('notes')
        .snapshots()
        .listen(
          (snapshot) async {
            try {
              final notes = snapshot.docs
                  .map(
                    (doc) => Note.fromFirestoreJson(
                      doc.data(),
                      uid: uid,
                      noteId: doc.id,
                    ),
                  )
                  .toList();
              await _isarNoteStore.putAll(notes);
            } catch (e, st) {
              debugPrint(
                '[FirestoreNoteSyncService] Snapshot process error: $e',
              );
              debugPrintStack(stackTrace: st);
            }
          },
          onError: (Object error, StackTrace st) async {
            debugPrint(
              '[FirestoreNoteSyncService] Snapshot listener error: $error',
            );
            debugPrintStack(stackTrace: st);
            await _restartAfterDelay();
          },
        );
  }

  Future<void> _restartAfterDelay() async {
    if (_isRestarting || !_started) {
      return;
    }
    _isRestarting = true;
    try {
      await Future<void>.delayed(const Duration(seconds: 3));
      if (_started) {
        await _attachUserListener(_auth.currentUser);
      }
    } finally {
      _isRestarting = false;
    }
  }

  Future<void> syncNoteById(String noteId, {String? uid}) async {
    final resolvedUid = uid ?? _auth.currentUser?.uid;
    if (resolvedUid == null || noteId.trim().isEmpty) {
      debugPrint(
        '[FirestoreNoteSyncService] Skipping syncNoteById: uid=$resolvedUid, noteId=$noteId',
      );
      return;
    }

    try {
      debugPrint(
        '[FirestoreNoteSyncService] Starting sync for note: $noteId (uid: $resolvedUid)',
      );

      final snap = await _firestore
          .collection('users')
          .doc(resolvedUid)
          .collection('notes')
          .doc(noteId)
          .get();

      if (!snap.exists) {
        debugPrint(
          '[FirestoreNoteSyncService] Note not found in Firestore: $noteId',
        );
        return;
      }

      final data = snap.data();
      if (data == null) {
        debugPrint('[FirestoreNoteSyncService] Note data is null: $noteId');
        return;
      }

      debugPrint(
        '[FirestoreNoteSyncService] Downloaded note from Firestore: $noteId',
      );

      final parsed = Note.fromFirestoreJson(
        data,
        uid: resolvedUid,
        noteId: noteId,
      );
      await _isarNoteStore.put(parsed);

      debugPrint(
        '[FirestoreNoteSyncService] Saved note to local Isar store: $noteId',
      );
    } catch (e, st) {
      debugPrint('[FirestoreNoteSyncService] ERROR syncing note $noteId: $e');
      debugPrintStack(stackTrace: st);
    }
  }

  Future<void> applyStatusFromPush({
    required String noteId,
    required String status,
  }) async {
    if (noteId.trim().isEmpty) {
      debugPrint(
        '[FirestoreNoteSyncService] Skipping applyStatusFromPush: empty noteId',
      );
      return;
    }

    try {
      debugPrint(
        '[FirestoreNoteSyncService] Applying status "$status" to note: $noteId',
      );

      final nextStatus = parseStatus(status);
      final existing = await _isarNoteStore.getByNoteId(noteId);
      if (existing == null) {
        debugPrint(
          '[FirestoreNoteSyncService] Note not found in local Isar store: $noteId',
        );
        return;
      }

      final updated = existing.copyWith(
        status: nextStatus,
        updatedAt: DateTime.now(),
        syncedAt: DateTime.now(),
      );

      await _isarNoteStore.put(updated);

      debugPrint(
        '[FirestoreNoteSyncService] Applied status change: $noteId → $nextStatus',
      );
    } catch (e, st) {
      debugPrint(
        '[FirestoreNoteSyncService] ERROR applying status to $noteId: $e',
      );
      debugPrintStack(stackTrace: st);
    }
  }
}

import 'package:http/http.dart' as http;

class HeaderClient extends http.BaseClient {
  HeaderClient(this._headers, [http.Client? inner])
      : _inner = inner ?? http.Client();

  final Map<String, String> _headers;
  final http.Client _inner;

  @override
  Future<http.StreamedResponse> send(http.BaseRequest request) {
    request.headers.addAll(_headers);
    return _inner.send(request);
  }

  @override
  void close() {
    _inner.close();
    super.close();
  }
}

