package com.adarshkumarverma.wishperlog

import io.flutter.plugin.common.MethodChannel

/**
 * Singleton holder so the NoteInputReceiver can access the Flutter MethodChannel
 * even when MainActivity may not be in the foreground.
 */
object FlutterEngineHolder {
    var channel: MethodChannel? = null
}

package com.adarshkumarverma.wishperlog

import android.Manifest
import android.content.pm.PackageManager
import android.content.Intent
import android.net.Uri
import android.os.Build
import android.provider.Settings
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import io.flutter.embedding.android.FlutterActivity
import io.flutter.embedding.android.FlutterActivityLaunchConfigs
import io.flutter.embedding.engine.FlutterEngine
import io.flutter.plugin.common.MethodChannel

class MainActivity : FlutterActivity() {
    private val CHANNEL = "wishperlog/overlay"
    private val REQUEST_RECORD_AUDIO = 4242
    private val noteReceiver = NoteInputReceiver()
    private var pendingMicPermissionResult: MethodChannel.Result? = null

    override fun getBackgroundMode(): FlutterActivityLaunchConfigs.BackgroundMode {
        return FlutterActivityLaunchConfigs.BackgroundMode.transparent
    }

    override fun configureFlutterEngine(flutterEngine: FlutterEngine) {
        super.configureFlutterEngine(flutterEngine)

        val channel = MethodChannel(flutterEngine.dartExecutor.binaryMessenger, CHANNEL)

        // Store channel globally so NoteInputReceiver can access it from any context
        FlutterEngineHolder.channel = channel

        channel.setMethodCallHandler { call, result ->
            when (call.method) {
                "show" -> {
                    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M && !Settings.canDrawOverlays(this)) {
                        result.error("PERMISSION_DENIED", "Overlay permission not granted", null)
                    } else {
                        val serviceIntent = Intent(this, OverlayForegroundService::class.java)
                        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O)
                            startForegroundService(serviceIntent)
                        else
                            startService(serviceIntent)
                        result.success(null)
                    }
                }
                "hide" -> {
                    stopService(Intent(this, OverlayForegroundService::class.java))
                    result.success(null)
                }
                "checkPermission" -> {
                    result.success(
                        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M)
                            Settings.canDrawOverlays(this)
                        else true
                    )
                }
                "requestPermission" -> {
                    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
                        startActivity(Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION, Uri.parse("package:$packageName")))
                    }
                    result.success(null)
                }
                "requestMicrophonePermission" -> {
                    if (ContextCompat.checkSelfPermission(this, Manifest.permission.RECORD_AUDIO) == PackageManager.PERMISSION_GRANTED) {
                        result.success(true)
                    } else {
                        if (pendingMicPermissionResult != null) {
                            result.error("REQUEST_IN_PROGRESS", "Microphone permission request already in progress", null)
                        } else {
                            pendingMicPermissionResult = result
                            ActivityCompat.requestPermissions(
                                this,
                                arrayOf(Manifest.permission.RECORD_AUDIO),
                                REQUEST_RECORD_AUDIO
                            )
                        }
                    }
                }
                "updateIslandState" -> {
                    @Suppress("UNCHECKED_CAST")
                    val args = call.arguments as? Map<String, Any?> ?: emptyMap()
                    val state = args["state"] as? String ?: "idle"
                    val message = args["message"] as? String
                    OverlayForegroundService.updateIsland(state, message)
                    result.success(null)
                }
                // KEY NEW METHOD: Flutter calls this after a background capture note is saved
                // so the native island can show the category + title pill
                "notifySaved" -> {
                    @Suppress("UNCHECKED_CAST")
                    val args = call.arguments as? Map<String, Any?> ?: emptyMap()
                    val title = args["title"] as? String ?: "Saved"
                    val category = args["category"] as? String ?: "general"
                    OverlayForegroundService.notifySaved(title, category)
                    result.success(null)
                }
                else -> result.notImplemented()
            }
        }

        // Register overlay note receiver (secondary - in case service receiver misses it)
        NoteInputReceiver.register(this, noteReceiver)
    }

    override fun onDestroy() {
        NoteInputReceiver.unregister(this, noteReceiver)
        FlutterEngineHolder.channel = null
        super.onDestroy()
    }

    override fun onRequestPermissionsResult(
        requestCode: Int,
        permissions: Array<out String>,
        grantResults: IntArray
    ) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults)

        if (requestCode == REQUEST_RECORD_AUDIO) {
            val granted = grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED
            pendingMicPermissionResult?.success(granted)
            pendingMicPermissionResult = null
        }
    }
}

package com.adarshkumarverma.wishperlog

import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.IntentFilter
import android.util.Log
import androidx.localbroadcastmanager.content.LocalBroadcastManager
import io.flutter.plugin.common.MethodChannel

/**
 * Receives captured note text from OverlayForegroundService and
 * forwards it to Flutter via MethodChannel — WITHOUT opening the app.
 *
 * KEY FIX: This receiver is now registered by the SERVICE itself (not MainActivity),
 * so it stays alive even when the app is in the background.
 * MainActivity still registers/unregisters a second copy for convenience when the
 * app is foregrounded (both are safe — Flutter handles duplicate captureNote calls via
 * the noteId dedup in IsarNoteStore).
 */
class NoteInputReceiver : BroadcastReceiver() {

    companion object {
        private const val TAG = "NoteInputReceiver"

        fun register(context: Context, receiver: NoteInputReceiver) {
            LocalBroadcastManager.getInstance(context)
                .registerReceiver(receiver, IntentFilter(OverlayForegroundService.ACTION_NOTE_CAPTURED))
        }

        fun unregister(context: Context, receiver: NoteInputReceiver) {
            try {
                LocalBroadcastManager.getInstance(context).unregisterReceiver(receiver)
            } catch (e: Exception) {
                Log.w(TAG, "unregister: already unregistered", e)
            }
        }
    }

    override fun onReceive(context: Context, intent: Intent) {
        if (intent.action != OverlayForegroundService.ACTION_NOTE_CAPTURED) return

        val text = intent.getStringExtra(OverlayForegroundService.EXTRA_TEXT) ?: return
        val source = intent.getStringExtra(OverlayForegroundService.EXTRA_SOURCE) ?: "overlay"

        val payload = mapOf(
            "text" to text,
            "source" to source
        )

        val channel = FlutterEngineHolder.channel
        if (channel == null) {
            Log.w(TAG, "captureNote dropped: Flutter channel unavailable (engine/activity not alive)")
            // When Flutter is not available, we cannot process the note.
            // The note will be re-attempted on next app open via Firestore sync.
            // TODO: consider storing in SharedPreferences and retrying on next launch.
            return
        }

        channel.invokeMethod("captureNote", payload, object : MethodChannel.Result {
            override fun success(result: Any?) {
                Log.d(TAG, "captureNote forwarded to Flutter (source=$source, len=${text.length})")
            }

            override fun error(errorCode: String, errorMessage: String?, errorDetails: Any?) {
                Log.e(TAG, "captureNote failed in Flutter: code=$errorCode, msg=$errorMessage")
            }

            override fun notImplemented() {
                Log.e(TAG, "captureNote failed: method not implemented on Flutter side")
            }
        })
    }
}

